'use client'

import {
  cn,
  DismissableLayer,
  useAnchorPosition,
  useSignal,
  useSignalEffect,
  useSignals,
} from '@cascivo/core'
import { useId, useRef, type KeyboardEvent, type ReactNode } from 'react'
import styles from './menu-button.module.css'

export interface MenuButtonItem {
  id: string
  label: ReactNode
  onSelect?: () => void
  disabled?: boolean
}

export interface MenuButtonProps {
  label: ReactNode
  items: MenuButtonItem[]
  variant?: 'primary' | 'secondary' | 'ghost'
  size?: 'sm' | 'md' | 'lg'
  disabled?: boolean
  align?: 'start' | 'end'
  labels?: { open?: string }
  className?: string
}

function focusItem(list: HTMLElement | null, index: number): void {
  if (!list) return
  const items = list.querySelectorAll<HTMLElement>('[role="menuitem"]:not([aria-disabled="true"])')
  const target = items[index < 0 ? items.length - 1 : index % items.length]
  target?.focus()
}

export function MenuButton({
  label,
  items,
  variant = 'secondary',
  size = 'md',
  disabled = false,
  align = 'start',
  labels,
  className,
}: MenuButtonProps) {
  useSignals()
  const open = useSignal(false)
  const triggerRef = useRef<HTMLButtonElement>(null)
  const menuRef = useRef<HTMLDivElement>(null)
  const menuId = useId()

  const { anchorStyle, floatingStyle } = useAnchorPosition({
    anchorRef: triggerRef,
    floatingRef: menuRef,
    placement: align === 'end' ? 'bottom-end' : 'bottom-start',
    enabled: open,
  })

  // Focus the first enabled item when the menu opens.
  useSignalEffect(() => {
    if (open.value) focusItem(menuRef.current, 0)
  })

  function openMenu(focusIndex: number): void {
    if (disabled) return
    open.value = true
    queueMicrotask(() => focusItem(menuRef.current, focusIndex))
  }

  function close(restoreFocus: boolean): void {
    open.value = false
    if (restoreFocus) triggerRef.current?.focus()
  }

  function handleTriggerKeyDown(e: KeyboardEvent<HTMLButtonElement>): void {
    if (e.key === 'ArrowDown' || e.key === 'Enter' || e.key === ' ') {
      e.preventDefault()
      openMenu(0)
    } else if (e.key === 'ArrowUp') {
      e.preventDefault()
      openMenu(-1)
    }
  }

  function handleItemKeyDown(e: KeyboardEvent<HTMLDivElement>): void {
    if (e.key === 'ArrowDown') {
      e.preventDefault()
      const next = e.currentTarget.nextElementSibling as HTMLElement | null
      if (next) next.focus()
      else focusItem(menuRef.current, 0)
    } else if (e.key === 'ArrowUp') {
      e.preventDefault()
      const prev = e.currentTarget.previousElementSibling as HTMLElement | null
      if (prev) prev.focus()
      else focusItem(menuRef.current, -1)
    } else if (e.key === 'Escape') {
      e.preventDefault()
      close(true)
    } else if (e.key === 'Tab') {
      close(false)
    }
  }

  function select(item: MenuButtonItem): void {
    if (item.disabled) return
    item.onSelect?.()
    close(true)
  }

  return (
    <div className={cn(styles['root'], className)}>
      <button
        ref={triggerRef}
        type="button"
        className={styles['trigger']}
        data-variant={variant}
        data-size={size}
        disabled={disabled}
        aria-haspopup="menu"
        aria-expanded={open.value}
        aria-controls={menuId}
        {...(labels?.open !== undefined && { 'aria-label': labels.open })}
        style={anchorStyle}
        onClick={() => {
          if (open.value) close(false)
          else openMenu(0)
        }}
        onKeyDown={handleTriggerKeyDown}
      >
        {label}
      </button>

      {open.value ? (
        <DismissableLayer onDismiss={() => close(true)}>
          <div
            ref={menuRef}
            id={menuId}
            role="menu"
            data-state="open"
            data-align={align}
            className={styles['menu']}
            style={floatingStyle}
          >
            {items.map((item) => (
              <div
                key={item.id}
                role="menuitem"
                tabIndex={-1}
                aria-disabled={item.disabled}
                className={styles['item']}
                onClick={() => select(item)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter' || e.key === ' ') {
                    e.preventDefault()
                    select(item)
                  } else {
                    handleItemKeyDown(e)
                  }
                }}
              >
                {item.label}
              </div>
            ))}
          </div>
        </DismissableLayer>
      ) : null}
    </div>
  )
}

@layer cascivo.component {
  .root {
    position: relative;
    display: inline-block;
  }

  .trigger {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: var(--cascivo-space-2);
    font-family: var(--cascivo-font-sans);
    font-weight: var(--cascivo-font-medium);
    line-height: var(--cascivo-leading-none);
    white-space: nowrap;
    cursor: pointer;
    border: 1px solid transparent;
    border-radius: var(--cascivo-radius-control);
    transition:
      background-color var(--cascivo-duration-150) var(--cascivo-ease-out),
      color var(--cascivo-duration-150) var(--cascivo-ease-out),
      box-shadow var(--cascivo-duration-150) var(--cascivo-ease-out);

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
    }

    &:disabled {
      opacity: 0.5;
      cursor: not-allowed;
      pointer-events: none;
    }

    &[data-size='sm'] {
      height: 2rem;
      padding-inline: var(--cascivo-space-3);
      font-size: var(--cascivo-text-sm);
    }

    &[data-size='md'] {
      height: 2.5rem;
      padding-inline: var(--cascivo-space-4);
      font-size: var(--cascivo-text-sm);
    }

    &[data-size='lg'] {
      height: 3rem;
      padding-inline: var(--cascivo-space-6);
      font-size: var(--cascivo-text-base);
    }

    &[data-variant='primary'] {
      background-color: var(--cascivo-color-primary);
      color: var(--cascivo-color-primary-fg);

      &:hover:not(:disabled) {
        background-color: var(--cascivo-color-primary-hover);
      }
    }

    &[data-variant='secondary'] {
      background-color: var(--cascivo-color-surface);
      color: var(--cascivo-color-text);
      border-color: var(--cascivo-color-border);

      &:hover:not(:disabled) {
        background-color: var(--cascivo-color-bg-subtle);
      }
    }

    &[data-variant='ghost'] {
      background-color: transparent;
      color: var(--cascivo-color-text);

      &:hover:not(:disabled) {
        background-color: var(--cascivo-color-bg-subtle);
      }
    }
  }

  .menu {
    z-index: var(--cascivo-z-dropdown);
    min-inline-size: 12rem;
    margin-block-start: var(--cascivo-space-1);
    padding: var(--cascivo-space-1);
    background: var(--cascivo-color-surface);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-overlay);
    box-shadow: var(--cascivo-shadow-md);

    opacity: 1;
    translate: 0 0;
    transition:
      opacity var(--cascivo-motion-enter),
      translate var(--cascivo-motion-enter);

    @starting-style {
      opacity: 0;
      translate: 0 calc(-1 * var(--cascivo-space-2));
    }
  }

  .item {
    display: flex;
    align-items: center;
    gap: var(--cascivo-space-2);
    padding: var(--cascivo-space-2) var(--cascivo-space-3);
    border-radius: var(--cascivo-radius-item);
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text);
    cursor: pointer;
    user-select: none;
    outline: none;

    &:hover,
    &:focus-visible {
      background: var(--cascivo-color-bg-subtle);
    }

    &[aria-disabled='true'] {
      opacity: 0.5;
      cursor: not-allowed;
    }
  }
}

@media (prefers-reduced-motion: reduce) {
  .menu {
    transition: none;
  }
}

@media (forced-colors: active) {
  .trigger {
    border: 1px solid ButtonText;
  }

  .trigger:focus-visible {
    outline: 2px solid Highlight;
    outline-offset: 2px;
  }

  .menu {
    border: 1px solid CanvasText;
  }

  .item:focus-visible {
    outline: 2px solid Highlight;
  }
}
